    47→func TestNewTools(t *testing.T) {
    48→	store := &mockDataStore{}
    49→	tools, err := NewTools(store, "proj-1")
    50→	if err != nil {
    51→		t.Fatalf("NewTools returned error: %v", err)
    52→	}
    53→	if len(tools) != 3 {
    54→		t.Fatalf("expected 3 tools, got %d", len(tools))
    55→	}
    56→
    57→	expectedNames := map[string]bool{
    58→		"get_releases":         false,
    59→		"get_release_detail":   false,
    60→		"list_context_sources": false,
    61→	}
    62→	for _, tool := range tools {
    63→		if _, ok := expectedNames[tool.Name()]; !ok {
    64→			t.Errorf("unexpected tool name: %s", tool.Name())
    65→		}
    66→		expectedNames[tool.Name()] = true
    67→	}
    68→	for name, found := range expectedNames {
    69→		if !found {
    70→			t.Errorf("expected tool %q not found", name)
    71→		}
    72→	}
    73→}
