    75→func TestGetReleases(t *testing.T) {
    76→	now := time.Now()
    77→	releasedAt := now.Add(-24 * time.Hour)
    78→	store := &mockDataStore{
    79→		releases: []models.Release{
    80→			{
    81→				ID:         "rel-1",
    82→				SourceID:   "src-1",
    83→				Version:    "v1.2.0",
    84→				RawData:    json.RawMessage(`{"notes": "bug fixes"}`),
    85→				ReleasedAt: &releasedAt,
    86→				CreatedAt:  now,
    87→			},
    88→			{
    89→				ID:        "rel-2",
    90→				SourceID:  "src-1",
    91→				Version:   "v1.1.0",
    92→				RawData:   json.RawMessage(`{}`),
    93→				CreatedAt: now.Add(-48 * time.Hour),
    94→			},
    95→		},
    96→		releasesTotal: 2,
    97→	}
    98→
    99→	f := &toolFactory{store: store, projectID: "proj-1"}
   100→
   101→	t.Run("default pagination", func(t *testing.T) {
   102→		out, err := f.getReleases(nil, GetReleasesInput{})
   103→		if err != nil {
   104→			t.Fatalf("getReleases error: %v", err)
   105→		}
   106→		if out.Total != 2 {
   107→			t.Errorf("expected total=2, got %d", out.Total)
   108→		}
   109→		if out.Page != 1 {
   110→			t.Errorf("expected page=1, got %d", out.Page)
   111→		}
   112→		if out.PerPage != 20 {
   113→			t.Errorf("expected perPage=20, got %d", out.PerPage)
   114→		}
   115→		if len(out.Releases) != 2 {
   116→			t.Fatalf("expected 2 releases, got %d", len(out.Releases))
   117→		}
   118→		if out.Releases[0].Version != "v1.2.0" {
   119→			t.Errorf("expected version v1.2.0, got %s", out.Releases[0].Version)
   120→		}
   121→		if out.Releases[0].ReleasedAt == "" {
   122→			t.Error("expected released_at to be set for first release")
   123→		}
   124→		if out.Releases[1].ReleasedAt != "" {
   125→			t.Error("expected released_at to be empty for second release")
   126→		}
   127→	})
   128→
   129→	t.Run("custom pagination", func(t *testing.T) {
   130→		out, err := f.getReleases(nil, GetReleasesInput{Page: 2, PerPage: 10})
   131→		if err != nil {
   132→			t.Fatalf("getReleases error: %v", err)
   133→		}
   134→		if out.Page != 2 {
   135→			t.Errorf("expected page=2, got %d", out.Page)
   136→		}
   137→		if out.PerPage != 10 {
   138→			t.Errorf("expected perPage=10, got %d", out.PerPage)
   139→		}
   140→	})
   141→
   142→	t.Run("clamps perPage", func(t *testing.T) {
   143→		out, err := f.getReleases(nil, GetReleasesInput{PerPage: 100})
   144→		if err != nil {
   145→			t.Fatalf("getReleases error: %v", err)
   146→		}
   147→		if out.PerPage != 20 {
   148→			t.Errorf("expected perPage clamped to 20, got %d", out.PerPage)
   149→		}
   150→	})
   151→
   152→	t.Run("store error", func(t *testing.T) {
   153→		errStore := &mockDataStore{err: fmt.Errorf("db down")}
   154→		ef := &toolFactory{store: errStore, projectID: "proj-1"}
   155→		_, err := ef.getReleases(nil, GetReleasesInput{})
   156→		if err == nil {
   157→			t.Fatal("expected error, got nil")
   158→		}
   159→	})
   160→}
