	}
	slog.Info("agent: LLM run finished",
		"run_id", run.ID,
		"event_count", eventCount,
		"output_length", len(finalText),
	)

	if finalText == "" {
		slog.Error("agent: produced no output",
			"run_id", run.ID,
			"project_id", run.ProjectID,
			"event_count", eventCount,
		)
