// parseReport attempts to parse the agent's text output as a SemanticReport JSON.
// It handles cases where the agent wraps the JSON in markdown code blocks or
// surrounds it with prose text.
func parseReport(text string) (*models.SemanticReport, error) {
	cleaned := strings.TrimSpace(text)

	// Strip markdown code fences if present.
	if strings.HasPrefix(cleaned, "```") {
		// Remove opening fence (with optional language tag).
		if idx := strings.Index(cleaned, "\n"); idx != -1 {
			cleaned = cleaned[idx+1:]
		}
		// Remove closing fence.
		if idx := strings.LastIndex(cleaned, "```"); idx != -1 {
			cleaned = cleaned[:idx]
		}
		cleaned = strings.TrimSpace(cleaned)
	}

	// Try direct parse first.
	var report models.SemanticReport
	if err := json.Unmarshal([]byte(cleaned), &report); err != nil {
		// Fallback: extract the first JSON object from the text.
		// LLMs sometimes wrap the JSON with prose like "Here is the report: {...}"
		start := strings.Index(cleaned, "{")
		end := strings.LastIndex(cleaned, "}")
		if start >= 0 && end > start {
			extracted := cleaned[start : end+1]
			if err2 := json.Unmarshal([]byte(extracted), &report); err2 != nil {
				return nil, fmt.Errorf("parse report JSON: %w", err)
			}
		} else {
			return nil, fmt.Errorf("parse report JSON: %w", err)
		}
	}

	if report.Summary == "" {
		return nil, fmt.Errorf("report is missing required 'summary' field")
	}

	return &report, nil
}

